const express = require('express');
const { WebSocketServer } = require('ws');
const http = require('http');

const app = express();
const server = http.createServer(app);
const wss = new WebSocketServer({ server });

// Configuration
const MAX_CONNECTIONS_PER_IP = 10;
const CONNECTION_TIMEOUT = 60000; // 60 seconds
const MAX_MESSAGE_SIZE = 64 * 1024; // 64KB
const MESSAGE_RATE_LIMIT = 100; // messages per minute

// Track connections by IP
const connectionsByIP = new Map();
const messageCountByClient = new Map();

// Helper: Extract client IP
function getClientIP(req) {
  return req.headers['x-forwarded-for']?.split(',')[0].trim() || 
         req.socket.remoteAddress;
}

// Helper: Check rate limit
function checkRateLimit(clientId) {
  const now = Date.now();
  const clientData = messageCountByClient.get(clientId) || { count: 0, resetTime: now + 60000 };

  if (now > clientData.resetTime) {
    clientData.count = 0;
    clientData.resetTime = now + 60000;
  }

  clientData.count++;
  messageCountByClient.set(clientId, clientData);

  return clientData.count <= MESSAGE_RATE_LIMIT;
}

// WebSocket connection handler
wss.on('connection', (ws, req) => {
  const clientIP = getClientIP(req);
  const clientId = `${clientIP}-${Date.now()}`;

  // Check per-IP connection limit
  const ipConnections = connectionsByIP.get(clientIP) || [];

  if (ipConnections.length >= MAX_CONNECTIONS_PER_IP) {
    console.warn(`Connection limit exceeded for IP: ${clientIP}`);
    ws.close(1008, 'Connection limit exceeded');
    return;
  }

  // Add to tracking
  ipConnections.push(ws);
  connectionsByIP.set(clientIP, ipConnections);

  console.log(`New connection from ${clientIP} (${ipConnections.length}/${MAX_CONNECTIONS_PER_IP})`);

  // Set up idle timeout
  let idleTimeout = setTimeout(() => {
    console.log(`Closing idle connection from ${clientIP}`);
    ws.close(1000, 'Idle timeout');
  }, CONNECTION_TIMEOUT);

  // Heartbeat mechanism
  ws.isAlive = true;
  ws.on('pong', () => {
    ws.isAlive = true;
    clearTimeout(idleTimeout);
    idleTimeout = setTimeout(() => {
      ws.close(1000, 'Idle timeout');
    }, CONNECTION_TIMEOUT);
  });

  // Message handler with rate limiting
  ws.on('message', (data) => {
    // Reset idle timeout on activity
    clearTimeout(idleTimeout);
    idleTimeout = setTimeout(() => ws.close(1000, 'Idle timeout'), CONNECTION_TIMEOUT);

    // Check message size
    if (data.length > MAX_MESSAGE_SIZE) {
      console.warn(`Message too large from ${clientIP}: ${data.length} bytes`);
      ws.close(1009, 'Message too large');
      return;
    }

    // Check rate limit
    if (!checkRateLimit(clientId)) {
      console.warn(`Rate limit exceeded for ${clientIP}`);
      ws.send(JSON.stringify({ error: 'Rate limit exceeded' }));
      return;
    }

    // Process message
    try {
      const message = JSON.parse(data);
      // Handle message...
      ws.send(JSON.stringify({ status: 'received' }));
    } catch (error) {
      ws.send(JSON.stringify({ error: 'Invalid message format' }));
    }
  });

  // Cleanup on close
  ws.on('close', () => {
    clearTimeout(idleTimeout);
    const connections = connectionsByIP.get(clientIP) || [];
    const index = connections.indexOf(ws);
    if (index > -1) {
      connections.splice(index, 1);
    }
    if (connections.length === 0) {
      connectionsByIP.delete(clientIP);
    } else {
      connectionsByIP.set(clientIP, connections);
    }
    messageCountByClient.delete(clientId);
    console.log(`Connection closed for ${clientIP}`);
  });

  ws.on('error', (error) => {
    console.error(`WebSocket error for ${clientIP}:`, error);
  });
});

// Heartbeat interval (30 seconds)
const heartbeatInterval = setInterval(() => {
  wss.clients.forEach((ws) => {
    if (ws.isAlive === false) {
      return ws.terminate();
    }
    ws.isAlive = false;
    ws.ping();
  });
}, 30000);

wss.on('close', () => {
  clearInterval(heartbeatInterval);
});

server.listen(3000, () => {
  console.log('WebSocket server running on port 3000');
  console.log(`Max connections per IP: ${MAX_CONNECTIONS_PER_IP}`);
  console.log(`Connection timeout: ${CONNECTION_TIMEOUT}ms`);
});

import org.springframework.context.annotation.Configuration;
import org.springframework.messaging.simp.config.MessageBrokerRegistry;
import org.springframework.web.socket.config.annotation.EnableWebSocketMessageBroker;
import org.springframework.web.socket.config.annotation.StompEndpointRegistry;
import org.springframework.web.socket.config.annotation.WebSocketMessageBrokerConfigurer;
import org.springframework.web.socket.config.annotation.WebSocketTransportRegistration;
import org.springframework.web.socket.server.HandshakeInterceptor;
import org.springframework.http.server.ServerHttpRequest;
import org.springframework.http.server.ServerHttpResponse;
import org.springframework.web.socket.WebSocketHandler;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

@Configuration
@EnableWebSocketMessageBroker
public class WebSocketConfig implements WebSocketMessageBrokerConfigurer {

    private static final int MAX_CONNECTIONS_PER_IP = 10;
    private static final Map<String, AtomicInteger> connectionsByIP = new ConcurrentHashMap<>();

    @Override
    public void configureMessageBroker(MessageBrokerRegistry config) {
        config.enableSimpleBroker("/topic", "/queue");
        config.setApplicationDestinationPrefixes("/app");
    }

    @Override
    public void registerStompEndpoints(StompEndpointRegistry registry) {
        registry.addEndpoint("/ws")
                .setAllowedOriginPatterns("https://yourdomain.com")
                .addInterceptors(new ConnectionLimitInterceptor())
                .withSockJS();
    }

    @Override
    public void configureWebSocketTransport(WebSocketTransportRegistration registration) {
        registration
            // Maximum time (ms) allowed for sending messages
            .setSendTimeLimit(15 * 1000)
            // Maximum buffer size for sending (512 KB)
            .setSendBufferSizeLimit(512 * 1024)
            // Maximum size for incoming messages (64 KB)
            .setMessageSizeLimit(64 * 1024)
            // Time limit for receiving messages
            .setTimeToFirstMessage(30 * 1000);
    }

    // Custom HandshakeInterceptor for connection limiting
    public static class ConnectionLimitInterceptor implements HandshakeInterceptor {

        @Override
        public boolean beforeHandshake(
                ServerHttpRequest request,
                ServerHttpResponse response,
                WebSocketHandler wsHandler,
                Map<String, Object> attributes) throws Exception {

            String clientIP = getClientIP(request);
            AtomicInteger count = connectionsByIP.computeIfAbsent(
                clientIP, 
                k -> new AtomicInteger(0)
            );

            int currentConnections = count.get();

            if (currentConnections >= MAX_CONNECTIONS_PER_IP) {
                System.out.println("Connection limit exceeded for IP: " + clientIP);
                response.setStatusCode(org.springframework.http.HttpStatus.TOO_MANY_REQUESTS);
                return false;
            }

            count.incrementAndGet();
            attributes.put("clientIP", clientIP);
            System.out.println("Connection accepted from " + clientIP + 
                             " (" + count.get() + "/" + MAX_CONNECTIONS_PER_IP + ")");
            return true;
        }

        @Override
        public void afterHandshake(
                ServerHttpRequest request,
                ServerHttpResponse response,
                WebSocketHandler wsHandler,
                Exception exception) {
            // Post-handshake logic if needed
        }

        private String getClientIP(ServerHttpRequest request) {
            String xff = request.getHeaders().getFirst("X-Forwarded-For");
            if (xff != null && !xff.isEmpty()) {
                return xff.split(",")[0].trim();
            }
            return request.getRemoteAddress().getAddress().getHostAddress();
        }
    }
}

// WebSocket Event Listener for cleanup
import org.springframework.context.event.EventListener;
import org.springframework.stereotype.Component;
import org.springframework.web.socket.messaging.SessionDisconnectEvent;
import org.springframework.web.socket.messaging.SessionConnectedEvent;

@Component
public class WebSocketEventListener {

    @EventListener
    public void handleWebSocketConnectListener(SessionConnectedEvent event) {
        System.out.println("New WebSocket connection: " + 
                         event.getMessage().getHeaders());
    }

    @EventListener
    public void handleWebSocketDisconnectListener(SessionDisconnectEvent event) {
        String clientIP = (String) event.getMessage()
            .getHeaders()
            .get("simpSessionAttributes", Map.class)
            .get("clientIP");

        if (clientIP != null) {
            AtomicInteger count = WebSocketConfig.connectionsByIP.get(clientIP);
            if (count != null) {
                int remaining = count.decrementAndGet();
                System.out.println("Connection closed for " + clientIP + 
                                 " (" + remaining + " remaining)");
                if (remaining <= 0) {
                    WebSocketConfig.connectionsByIP.remove(clientIP);
                }
            }
        }
    }
}

